// Postcode prefix map — handles multi-character and single-character prefixes
const POSTCODE_MAP: Record<string, string> = {
  // London multi-char first
  EC: 'EC', NW: 'NW', SE: 'SE', SW: 'SW', WC: 'WC',
  // Other multi-char
  LS: 'LS', BS: 'BS', NE: 'NE', EH: 'EH', CF: 'CF', NG: 'NG', SO: 'SO',
  // Single char
  B: 'B', E: 'E', N: 'N', W: 'W', M: 'M', L: 'L', S: 'S',
};

export function getRegionKey(postcode: string): string | null {
  const clean = postcode.trim().toUpperCase().replace(/\s/g, '');
  // Try 2-char prefix first, then 1-char
  const two = clean.substring(0, 2);
  const one = clean.substring(0, 1);
  return POSTCODE_MAP[two] ?? POSTCODE_MAP[one] ?? null;
}

export function getJobsForPostcode(postcode: string, trade: string): { regionData: RegionData | null; jobs: Job[]; filtered: number } {
  const key = getRegionKey(postcode);
  if (!key) return { regionData: null, jobs: [], filtered: 0 };

  const regionData = JOBS[key];
  if (!regionData) return { regionData: null, jobs: [], filtered: 0 };

  const tradeKey = trade === 'electrical' ? 'electrical'
    : trade === 'plumbing' ? 'plumbing'
    : trade === 'heating' ? 'heating'
    : trade === 'building' ? 'building'
    : 'general';

  let jobs = regionData.jobs[tradeKey] ?? [];

  // Fallback: if no jobs for selected trade, pull from all trades
  if (jobs.length === 0) {
    jobs = Object.values(regionData.jobs).flat();
  }

  // Sort: TODAY first, THIS WEEK second, FLEXIBLE last
  const urgencyOrder: Record<Urgency, number> = { TODAY: 0, 'THIS WEEK': 1, FLEXIBLE: 2 };
  const sorted = [...jobs].sort((a, b) => urgencyOrder[a.urgency] - urgencyOrder[b.urgency]);

  // Count filtered-out (simulate rejected leads = 60-70% of raw pool)
  const filtered = Math.round(sorted.length * 1.8 + 2);

  return { regionData, jobs: sorted, filtered };
}

export default JOBS;

